function burgerMenu(){const e=document.querySelector(".burger"),t=document.querySelector(".menu"),o=document.querySelector("body");e.addEventListener("click",()=>{t.classList.contains("active")?(t.classList.remove("active"),e.classList.remove("active-burger"),o.classList.remove("locked")):(t.classList.add("active"),e.classList.add("active-burger"),o.classList.add("locked"))}),window.addEventListener("resize",()=>{window.innerWidth>991.98&&(t.classList.remove("active"),e.classList.remove("active-burger"),o.classList.remove("locked"))})}function fixedNav(){const e=document.querySelector("nav");window.scrollY>=800?e.classList.add("fixed__nav"):e.classList.remove("fixed__nav")}function scrollLinks(){const e=document.querySelectorAll("[data-goto]"),t=document.body,o=document.querySelector(".burger"),c=document.querySelector(".menu");if(e.length>0){function s(e){const s=e.target;if(s.dataset.goto&&document.querySelector(s.dataset.goto)){const r=document.querySelector(s.dataset.goto).getBoundingClientRect().top+pageYOffset-document.querySelector("nav").offsetHeight;o.classList.contains("active-burger")&&(o.classList.remove("active-burger"),t.classList.remove("locked"),c.classList.remove("active")),window.scrollTo({top:r,behavior:"smooth"}),e.preventDefault()}}e.forEach(e=>{e.addEventListener("click",s)})}}burgerMenu(),window.addEventListener("scroll",fixedNav),scrollLinks();